  // =========================================================================
  // LABEL
  // =========================================================================
  function labelFor(score) {
    if (score >=  0.6) return 'very_positive';
    if (score >=  0.2) return 'positive';
    if (score >  -0.2) return 'neutral';
    if (score > -0.6)  return 'negative';
    return 'very_negative';
  }

  // =========================================================================
