        tokenLower:      tok.tokenLower,
        lemma:           lookup.lemma,
        baseScore:       baseScore,
        negated:         negated,
        intensifierMult: mult,
        effectiveScore:  effective,
        lookup:          lookup.lookup,
        index:           i,
        charStart:       tok.start,
        charEnd:         tok.end
