      score:       normalized,
      text:        text || '',
      wordsScored: scoredCount,
      wordsTotal:  tokens.length,
      raw:         rawSum,
      average:     average,
      label:       labelFor(normalized),
      matches:     matches,
      positive:    positive,
      negative:    negative,
      tokens:      tokens.map(function (t) { return t.token; }),
